class BatchProcessor:
    def __init__(self, flush_threshold=5000):
        self.results_buffer = []
        self.flush_threshold = flush_threshold
        self.total_flushed = []

    def process_batch(self, records):
        for record in records:
            result = self.transform(record)
            self.results_buffer.append(result)
            if len(self.results_buffer) >= self.flush_threshold:
                self.flush_buffer()
        return len(records)

    def transform(self, record):
        return {
            'id': record['id'],
            'value': record['value'] * 2,
            'processed': True
        }

    def flush_buffer(self):
        batch = self.results_buffer
        self.results_buffer = []
        self.total_flushed.extend(batch)
        return batch

