class MockRedis:
    def __init__(self, max_conn=4):
        self.data = {}
        self.max_conn = max_conn
        self.active = 0
    def get_connection(self):
        if self.active >= self.max_conn:
            raise ConnectionError('max connections reached')
        self.active += 1
        return MockRedisConn(self)
    def release_connection(self, conn):
        self.active -= 1

def test_connections_released_on_success():
    redis = MockRedis(max_conn=4)
    mgr = SessionManager(redis)
    for i in range(10):
        mgr.create_session(f'user{i}', f'token{i}')
    assert redis.active <= redis.max_conn

def test_connections_released_on_error():
    redis = MockRedis(max_conn=4)
    mgr = SessionManager(redis)
    # Force errors and check connections are still released
    for i in range(10):
        try:
            mgr.create_session(f'user{i}', f'token{i}')
        except Exception:
            pass
    assert redis.active <= redis.max_conn, f'Leaked connections: {redis.active} active'

