import time

class RateLimiter:
    def __init__(self, limit=100, window_seconds=60):
        self.limit = limit
        self.window = window_seconds
        self.counters = {}  # user_id -> (count, window_start)

    def is_allowed(self, user_id):
        now = time.time()
        if user_id not in self.counters:
            self.counters[user_id] = (0, now)

        count, window_start = self.counters[user_id]

        # Reset window if expired
        if now - window_start >= self.window:
            self.counters[user_id] = (0, now)
            count = 0

        # BUG: >= instead of > means limit of 100 only allows 99
        if count >= self.limit:
            return False

        self.counters[user_id] = (count + 1, window_start if count > 0 else now)
        return True

